サンプルプログラムの解説

共通部
#include &lt;Scrobo.h&gt;

Scrobo robo = Scrobo();

void setup()
{
  Serial.begin(38400); // Open serial port at 38400 [baud]
  Serial.println("Connected");
}
モータ制御用ライブラリをインクルードし，インスタンス（robo）を作る． これはScroboライブラリで用意されている関数を使う場合に必要となる．
7行目で通信速度38400 baudでPCとマイコン間のシリアル通信を開始する．

sensor_checker
1秒ごとに6個のアナログセンサの出力値を読み取り，シリアル通信に書き込むプログラムである．
void loop()
{
  // Read analog inputs
  int ball_left = analogRead(0);   // A0
  int ball_center = analogRead(1); // A1
  int ball_right = analogRead(2);  // A2
  int range = analogRead(3);       // A3
  int floor_left = analogRead(6);  // A6
  int floor_right = analogRead(7); // A7

  // Serial outputs
  Serial.print(ball_left);
  Serial.print(",");
  Serial.print(ball_center);
  Serial.print(",");
  Serial.print(ball_right);
  Serial.print(",");
  Serial.print(range);
  Serial.print(",");
  Serial.print(floor_left);
  Serial.print(",");
  Serial.print(floor_right);
  Serial.println();

  // Wait 1 sec
  delay(1000);
}
4–9行目は，各行でひとつずつアナログセンサの値を読み取り，整数型の変数に格納している． analogRead関数の引数は，センサが接続されているマイコンボードのポート番号である． センサは0–5 Vの電圧値を出力し，それをマイコンのA/D変換ボードが0–1023の整数値に変換する．
12–23行目は，変数に保存したデータをシリアル通信でPC宛に送信している． ダブルクォートで囲われた(“,”)は，区切り用のカンマを書くため． printlnは末尾に改行を付加するプリント文で，23行目は改行のみを送信している．
最後に，26行目にて1000ミリ秒 = 1秒待機する． 1秒経過後にloop関数の内容をすべて実行し終えたことになり，センサ出力を読み取る冒頭部に戻る．

motor_checker
左右の走行モータ（M1, M2）とドリブルモータ（M3）の動作テストを行うプログラムである．
void loop() {
  delay(2000);

  // Move forward
  robo.setSpeedM1(100);
  robo.setSpeedM2(100);
  delay(1500);

  // Stop
  robo.setSpeedM1(0);
  robo.setSpeedM2(0);
  delay(1000);

  // Move backward
  robo.setSpeedM1(-100);
  robo.setSpeedM2(-100);
  delay(1500);

  // Stop
  robo.setSpeedM1(0);
  robo.setSpeedM2(0);
  delay(1000);

  // Zigzag
  for (int i = 0; i &lt; 4; i++) {
    robo.setSpeedM1(100);
    robo.setSpeedM2(30);
    delay(500);
    robo.setSpeedM1(30);
    robo.setSpeedM2(100);
    delay(500);
  }
  robo.setSpeedM1(0);
  robo.setSpeedM2(0);
  delay(1000);

  // Turn left
  robo.setSpeedM1(-100);
  robo.setSpeedM2(100);
  delay(1500);

  // Stop
  robo.setSpeedM1(0);
  robo.setSpeedM2(0);
  delay(1000);

  // Turn right
  robo.setSpeedM1(100);
  robo.setSpeedM2(-100);
  delay(1500);

  // Stop
  robo.setSpeedM1(0);
  robo.setSpeedM2(0);
  delay(1000);

  // Dribbling
  robo.setSpeedM3(100);  // forward
  delay(2000);
  robo.setSpeedM3(0);  // stop
  delay(1000);
  robo.setSpeedM3(-100);  // reverse
  delay(2000);
  robo.setSpeedM3(0);  // stop
  delay(1000);

  // Stop and wait
  robo.setSpeedM3(0);
  while (1) {}
}
冒頭のdelay(2000)によって，電源ONから2秒後にモータが動き出す．
5行目のrobo.setSpeedM1(100)は，左モータ(M1)のデューティ比を100に設定する． デューティ比は，PWM制御においてHighの電圧を加える割合であり，雑に言えば，モータの回転速度を決めるパラメータである1． このプログラムでは\(-255--255\)の値を指定できる（が定格電圧の関係で最大100としている）． 0で停止，正で前進方向，負で後退方向に回転する．
robo.は，setup関数の前に作成したScroboクラスのインスタンスで，setSpeedM1関数を使うために必要である． 6行目のsetSpeedM2は同じく右モータ（M2）のデューティ比を設定する．
7行目でこの状態を1.5秒維持する． この，delayを書かないと何が起こるか？ 5行目から6行目へ移るタイムラグはマイコンの実行速度によるが，体感としてはほぼゼロである． 同じように10行目まで，ほぼタイムラグなしで実行される． つまり，モータのデューティ比を100に設定した次の瞬間，10, 11行目でデューティ比を0に設定し直すことになり，モータは回転しない．
26行目以降のように，左右のモータで速度差をつけると，ロボットを旋回させることができる． 58行目のドリブルモータ（M3）の回転速度・方向指定も走行モータと同様である．
最後に，69行目は無限ループであり，ひととおりモータテストが終わったら，loop関数の内容を繰り返すこと無くロボットを停止させる動作を実現している．

スケッチ編集
今回は回路の編集は行わず，Arduinoスケッチ1のみ編集する． 回路を編集する場合は，GUIで素子を追加したり配線を接続したりする．
右上の「コード」ボタンを押すと，回路素子画面とスケッチ編集画面を切り替えられる． 初期状態では下記のスケッチが実装されているので，これを書き換えて所望の動作を実現する．
void setup() {
  pinMode(13, OUTPUT); // 13番ピンを出力モードに設定
  Serial.begin(9600);  // シリアル通信開始(通信速度9600)
}

void loop() {
  //// LEDチカチカ
  digitalWrite(13, HIGH); // 13番ピンを HIGH = 5V に設定
  delay(250); // 250 ms の間何もしない = 点灯を維持
  digitalWrite(13, LOW); // 13番ピンを LOW = 0V に設定
  delay(250); // 250 ms の間何もしない = 消灯を維持

  //// 可変抵抗器の電圧をシリアルモニタに表示
  int sliderValue = analogRead(0); //A0ピンの電圧値を読む
  Serial.println(sliderValue); //電圧値をモニタに出力
}

スケッチの保存
さっそくスケッチを作成してみよう． IDEを起動して「ファイル」メニューの「新規スケッチ」を選択すると，スケッチの雛形が作成される．
void setup() {
  // put your setup code here, to run once:

}

void loop() {
  // put your main code here, to run repeatedly:

}
Arduinoのスケッチファイルは，ファイル名と同名のフォルダに格納しなければならない． IDEの保存機能を使うと，自動的に格納フォルダが作成される． 先程のスケッチの雛形を，そのままblinkという名前をつけて「保存」（Ctrl+S）しよう． デフォルトの保存先は，マイドキュメント（macOSならユーザホームの書類）のArduinoフォルダ以下である． 保存先を確認すると，Arduinoフォルダ内にblinkフォルダが作成され，その下にテキストファイルblink.inoが作成されている．






Importantスケッチ名の制約



スケッチファイルは，ファイル名と同名のフォルダに格納しなければならない．ファイル名は半角英数，スペースなし．


ファイル名の制約について，守らなくても問題ない環境もあるとは思うが，守っておくほうが無難である．
